import assert from 'node:assert/strict'
import { test } from 'node:test'

import { AgentOrchestrator } from '../../src/main/services/agentOrchestrator'
import { DEFAULT_SETTINGS } from '../../src/main/types'

/**
 * Test helper to mock executeReadOnlySql and record query strings.
 * This allows us to verify the exact SQL generated by deterministic paths
 * without requiring a real database connection.
 */
class SqlQueryRecorder {
  private queries: string[] = []

  record(query: string): void {
    this.queries.push(query)
  }

  getQueries(): string[] {
    return this.queries
  }

  getLastQuery(): string | undefined {
    return this.queries[this.queries.length - 1]
  }

  clear(): void {
    this.queries = []
  }
}

function createMockAgentOrchestrator(recorder: SqlQueryRecorder): AgentOrchestrator {
  const settings = structuredClone(DEFAULT_SETTINGS)
  settings.sql.database = 'Sepidar01'
  settings.sql.server = '127.0.0.1'
  settings.sql.port = 58033
  settings.sql.user = 'damavand'
  settings.sql.password = 'test'

  const orchestrator = new AgentOrchestrator({
    geminiClient: {
      chat: async () => ({
        text: '',
        raw: {},
        toolCalls: []
      })
    },
    getSettings: () => settings,
    executeReadOnlySql: async (query: string) => {
      recorder.record(query)
      return []
    },
    executeMetadataSql: async () => [],
    auditLog: {
      write: async () => undefined
    }
  })

  return orchestrator
}

test('U0.3: get_trial_balance should use [schema].[table] quoting, not [schema.table]', async () => {
  const recorder = new SqlQueryRecorder()
  const orchestrator = createMockAgentOrchestrator(recorder)

  const settings = orchestrator['getSettings']()
  const conversationMemory = {
    conversationId: 'test',
    notes: [],
    facts: {
      companyNames: [],
      fiscalYears: [],
      branchNames: [],
      dateRange: null,
      confirmedMappings: {}
    },
    lastUserPrompt: 'تراز آزمایشی سال ۱۴۰۲',
    lastAssistantOutcome: null,
    lastToolTrace: [],
    touchedAt: Date.now()
  }
  await orchestrator['tryResolveDeterministicFinancialTool'](
    'get_trial_balance',
    settings,
    conversationMemory,
    new AbortController().signal
  )

  const query = recorder.getLastQuery()
  assert.ok(query, 'A SQL query should have been generated')

  // The query should use [ACC].[VoucherItem] and [ACC].[Voucher], NOT [ACC.VoucherItem] or [ACC.Voucher]
  assert.ok(
    query!.includes('[ACC].[VoucherItem]'),
    `Query should contain [ACC].[VoucherItem] but got: ${query}`
  )
  assert.ok(
    query!.includes('[ACC].[Voucher]'),
    `Query should contain [ACC].[Voucher] but got: ${query}`
  )
  assert.ok(
    !query!.includes('[ACC.VoucherItem]'),
    `Query should NOT contain [ACC.VoucherItem] but got: ${query}`
  )
  assert.ok(
    !query!.includes('[ACC.Voucher]'),
    `Query should NOT contain [ACC.Voucher] but got: ${query}`
  )
})

