test('U0.4: get_cash_bank_balance should use [schema].[table] quoting', async () => {
  const recorder = new SqlQueryRecorder()
  const orchestrator = createMockAgentOrchestrator(recorder)

  const settings = orchestrator['getSettings']()
  const conversationMemory = {
    conversationId: 'test',
    notes: [],
    facts: {
      companyNames: [],
      fiscalYears: [],
      branchNames: [],
      dateRange: null,
      confirmedMappings: {}
    },
    lastUserPrompt: 'مانده نقد و بانک',
    lastAssistantOutcome: null,
    lastToolTrace: [],
    touchedAt: Date.now()
  }
  await orchestrator['tryResolveDeterministicFinancialTool'](
    'get_cash_bank_balance',
    settings,
    conversationMemory,
    new AbortController().signal
  )

  const queries = recorder.getQueries()
  assert.ok(queries.length > 0, 'SQL queries should have been generated')

  // Check that all queries use proper [schema].[table] quoting
  for (const query of queries) {
    assert.ok(
      !query.includes('[RPA.CashBalance]'),
      `Query should NOT contain [RPA.CashBalance] but got: ${query}`
    )
    assert.ok(
      !query.includes('[RPA.BankAccountBalance]'),
      `Query should NOT contain [RPA.BankAccountBalance] but got: ${query}`
    )
  }

  // At least one query should use proper quoting
  const hasProperQuoting = queries.some(
    (q) => q.includes('[RPA].[CashBalance]') || q.includes('[RPA].[BankAccountBalance]')
  )
  assert.ok(hasProperQuoting, `At least one query should use [RPA].[CashBalance] or [RPA].[BankAccountBalance]`)
})

test('U2.3: get_account_balance with fiscal year filters by year', async () => {
  const recorder = new SqlQueryRecorder()
  const orchestrator = createMockAgentOrchestrator(recorder)

  const settings = orchestrator['getSettings']()
  const conversationMemory = {
    conversationId: 'test',
    notes: [],
    facts: {
      companyNames: [],
      fiscalYears: [],
      branchNames: [],
      dateRange: null,
      confirmedMappings: {}
    },
    lastUserPrompt: 'مانده بدهکار حساب سال ۱۴۰۲',
    lastAssistantOutcome: null,
    lastToolTrace: [],
    touchedAt: Date.now()
  }
  await orchestrator['tryResolveDeterministicFinancialTool'](
    'get_account_balance',
    settings,
    conversationMemory,
    new AbortController().signal,
    undefined,
    'مانده بدهکار حساب سال ۱۴۰۲'
  )

  const query = recorder.getLastQuery()
  assert.ok(query, 'A SQL query should have been generated')

  assert.ok(
    query!.includes("fy.Title = N'1402'"),
    `Query should contain fiscal year filter fy.Title = N'1402' but got: ${query}`
  )
  assert.ok(
    query!.includes('[ACC].[VoucherItem]'),
    `Query should contain [ACC].[VoucherItem] but got: ${query}`
  )
  assert.ok(
    query!.includes('[FMK].[FiscalYear]'),
    `Query should contain [FMK].[FiscalYear] but got: ${query}`
  )
})

