test('U4.4: isSalesGrowthPercentPrompt triggers for comparative multi-period without %', async () => {
  const recorder = new SqlQueryRecorder()
  const orchestrator = createMockAgentOrchestrator(recorder)

  // Test that comparative multi-period prompts (e.g., "فروش 1403 در مقابل 1402")
  // trigger the sales growth percentage path even without explicit '%' keyword
  const prompt1 = 'فروش 1403 در مقابل 1402'
  const prompt2 = 'مقایسه فروش سال 1402 و 1403'
  const prompt3 = 'فروش 1403 نسبت به 1402'

  assert.ok(
    orchestrator['isSalesGrowthPercentPrompt'](prompt1),
    `Prompt "${prompt1}" should trigger sales growth percentage path`
  )
  assert.ok(
    orchestrator['isSalesGrowthPercentPrompt'](prompt2),
    `Prompt "${prompt2}" should trigger sales growth percentage path`
  )
  assert.ok(
    orchestrator['isSalesGrowthPercentPrompt'](prompt3),
    `Prompt "${prompt3}" should trigger sales growth percentage path`
  )
})
